import java.util.ArrayList;import java.util.List;import java.util.Map;
final class StatePattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}interface State{String name();State handle(String event);}
record NamedState(String name,Map<String,String>transitions)implements State{public State handle(String event){String target=transitions.get(event);if(target==null)throw new PatternException("invalid_transition");return states().get(target);}}
static Map<String,State>states(){return Map.of("queued",new NamedState("queued",Map.of("start","running","cancel","cancelled")),"running",new NamedState("running",Map.of("complete","completed","fail","failed")),"failed",new NamedState("failed",Map.of("retry","running","cancel","cancelled")),"completed",new NamedState("completed",Map.of()),"cancelled",new NamedState("cancelled",Map.of()));}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){State current=states().get(String.valueOf(input.get("initial")));if(current==null)throw new PatternException("unknown_state");List<String>history=new ArrayList<>();history.add(current.name());for(Object event:(List<Object>)input.getOrDefault("events",List.of())){current=current.handle(String.valueOf(event));history.add(current.name());}return Map.of("final",current.name(),"history",history);}}
